import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useMeta } from '../../contexts/MetaContext';
import { buildFileToPathIndex, resolveInternalDocHref } from '../../utils/docLinkResolver';
import { flattenChapters } from '../../utils/navigationHelpers';

// The file->path index is derived purely from the active book's meta, a stable
// object from MetaContext, so cache one index per meta and share it across every
// link render. WeakMap lets superseded metas be garbage-collected.
const fileToPathIndexCache = new WeakMap();

function getFileToPathIndex(meta) {
  if (!meta) {
    return null;
  }
  let index = fileToPathIndexCache.get(meta);
  if (!index) {
    index = buildFileToPathIndex(flattenChapters(meta));
    fileToPathIndexCache.set(meta, index);
  }
  return index;
}

// Renders a Markdown link. Internal document links (./sibling.md, ../x.md,
// rust-course's /src/foo.md) are resolved to in-site routes and navigated
// client-side; everything else (external links, anchors, unknown targets) falls
// back to a plain <a> with the original href — see utils/docLinkResolver.
//
// Lives in its own module (not markdownRenderers) so it can be unit-tested
// without importing the ESM-only react-markdown stack.
export default function DocLink({ node, children, href = '', currentFile = '', ...rest }) {
  const navigate = useNavigate();
  const { meta } = useMeta();
  const resolved = resolveInternalDocHref({
    href,
    currentFile,
    fileToPath: getFileToPathIndex(meta)
  });

  if (!resolved) {
    return <a className="doc-link" href={href} {...rest}>{children}</a>;
  }

  const target = resolved.anchor ? `${resolved.to}#${resolved.anchor}` : resolved.to;

  const handleClick = (event) => {
    // Let the browser handle new-tab / new-window / non-primary-button clicks.
    if (
      event.defaultPrevented
      || event.button !== 0
      || event.metaKey
      || event.ctrlKey
      || event.shiftKey
      || event.altKey
      || rest.target === '_blank'
    ) {
      return;
    }
    event.preventDefault();
    navigate(target);
  };

  return (
    <a className="doc-link" {...rest} href={target} onClick={handleClick}>
      {children}
    </a>
  );
}
