import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import ReactDOM from 'react-dom';
import { useNavigate } from 'react-router-dom';
import { HiSearch, HiX, HiOutlineClock } from 'react-icons/hi';
import { loadBookIndex, searchBook, queryHighlightTerms, splitByTerms } from '../../services/search/searchClient';
import { buildSearchJumpState } from '../../services/search/searchJump';
import './SearchModal.css';

const RESULT_LIMIT = 30;
const DEBOUNCE_MS = 90;
const HISTORY_LIMIT = 5;

const historyKey = (bookId) => `beatai:search-history:${bookId || 'default'}`;

// Past search terms live in localStorage, scoped per book. Reads/writes are
// defensive: private-mode or a corrupted value should degrade to "no history"
// rather than throw and break the whole modal.
function loadHistory(bookId) {
  try {
    const raw = window.localStorage.getItem(historyKey(bookId));
    const arr = raw ? JSON.parse(raw) : [];
    return Array.isArray(arr)
      ? arr.filter((t) => typeof t === 'string' && t.trim()).slice(0, HISTORY_LIMIT)
      : [];
  } catch {
    return [];
  }
}

function saveHistory(bookId, list) {
  try {
    window.localStorage.setItem(historyKey(bookId), JSON.stringify(list.slice(0, HISTORY_LIMIT)));
  } catch {
    // ignore quota / unavailable storage
  }
}

// Render text with each query-term hit wrapped in <mark>, reusing the shared
// matching primitive so modal snippets and in-doc flashes highlight identically.
function highlight(text, terms) {
  return splitByTerms(text, terms).map((seg, i) =>
    seg.isHit
      ? <mark key={i} className="book-search-hit">{seg.text}</mark>
      : <React.Fragment key={i}>{seg.text}</React.Fragment>
  );
}

function SearchModal({ bookId, onClose }) {
  const navigate = useNavigate();
  const inputRef = useRef(null);
  const listRef = useRef(null);
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [selected, setSelected] = useState(0);
  // 'loading' until the book's index is fetched, then 'ready' or 'empty'.
  const [indexState, setIndexState] = useState('loading');
  // Whether this book indexes body text (e.g. 'titles'-mode books index only
  // article titles -> empty `idx`). When it doesn't, the snippet is preview-only
  // context, so we show it but don't highlight it — otherwise marking a term in
  // the body would wrongly imply the body was searched.
  const [bodyIndexed, setBodyIndexed] = useState(true);
  const [history, setHistory] = useState(() => loadHistory(bookId));
  const indexRef = useRef(null);

  const terms = useMemo(() => queryHighlightTerms(query), [query]);

  // Re-sync history when switching books (the modal may be reused across books).
  useEffect(() => {
    setHistory(loadHistory(bookId));
  }, [bookId]);

  // Record a term the user actually acted on (selected a result for). Dedupe to
  // the front and cap at HISTORY_LIMIT so the freshest 5 are kept.
  const remember = useCallback((raw) => {
    const term = (raw || '').trim();
    if (!term) {
      return;
    }
    setHistory((prev) => {
      const next = [term, ...prev.filter((t) => t !== term)].slice(0, HISTORY_LIMIT);
      saveHistory(bookId, next);
      return next;
    });
  }, [bookId]);

  const removeHistory = useCallback((term) => {
    setHistory((prev) => {
      const next = prev.filter((t) => t !== term);
      saveHistory(bookId, next);
      return next;
    });
  }, [bookId]);

  const clearHistory = useCallback(() => {
    setHistory([]);
    saveHistory(bookId, []);
  }, [bookId]);

  const applyHistory = useCallback((term) => {
    setQuery(term);
    inputRef.current?.focus();
  }, []);

  // Load the current book's index once when the modal opens.
  useEffect(() => {
    let alive = true;
    setIndexState('loading');
    loadBookIndex(bookId).then((index) => {
      if (!alive) {
        return;
      }
      indexRef.current = index;
      setBodyIndexed(Boolean(index && index.idx && Object.keys(index.idx).length));
      setIndexState(index && index.secs && index.secs.length ? 'ready' : 'empty');
    });
    return () => {
      alive = false;
    };
  }, [bookId]);

  // Focus the input on open and lock the background from scrolling.
  useEffect(() => {
    inputRef.current?.focus();
    const prevOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = prevOverflow;
    };
  }, []);

  // Debounced query -> results.
  useEffect(() => {
    if (indexState !== 'ready') {
      setResults([]);
      return undefined;
    }
    const handle = setTimeout(() => {
      const next = searchBook(indexRef.current, query, { limit: RESULT_LIMIT });
      setResults(next);
      setSelected(0);
    }, DEBOUNCE_MS);
    return () => clearTimeout(handle);
  }, [query, indexState]);

  const go = useCallback((result) => {
    if (!result) {
      return;
    }
    remember(query);
    onClose();
    // Carry the search-jump payload (flag + query terms) so the target page can
    // flash the actual hits inside the landed-on section. See
    // hooks/useSearchJumpHighlight.
    navigate(result.url, { state: buildSearchJumpState(terms) });
  }, [navigate, onClose, terms, remember, query]);

  // Keyboard: navigate the result list, open on Enter, close on Esc.
  const handleKeyDown = (event) => {
    if (event.key === 'Escape') {
      event.preventDefault();
      onClose();
      return;
    }
    if (event.key === 'ArrowDown') {
      event.preventDefault();
      setSelected((s) => Math.min(s + 1, results.length - 1));
      return;
    }
    if (event.key === 'ArrowUp') {
      event.preventDefault();
      setSelected((s) => Math.max(s - 1, 0));
      return;
    }
    if (event.key === 'Enter') {
      event.preventDefault();
      go(results[selected]);
    }
  };

  // Keep the highlighted result scrolled into view.
  useEffect(() => {
    const el = listRef.current?.querySelector('.book-search-item.is-selected');
    el?.scrollIntoView({ block: 'nearest' });
  }, [selected, results]);

  const renderBody = () => {
    if (indexState === 'loading') {
      return <div className="book-search-status">正在加载本书索引…</div>;
    }
    if (indexState === 'empty') {
      return <div className="book-search-status">本书暂无可搜索内容</div>;
    }
    if (!query.trim()) {
      if (history.length) {
        return (
          <div className="book-search-history">
            <div className="book-search-history-head">
              <span>最近搜索</span>
              <button
                type="button"
                className="book-search-history-clear"
                onClick={clearHistory}
              >
                清空
              </button>
            </div>
            <ul className="book-search-list">
              {history.map((term) => (
                <li key={term} className="book-search-history-row">
                  <button
                    type="button"
                    className="book-search-item book-search-history-item nav-highlight-link"
                    onClick={() => applyHistory(term)}
                  >
                    <HiOutlineClock className="book-search-history-icon" aria-hidden="true" />
                    <span className="book-search-history-term">{term}</span>
                  </button>
                  <button
                    type="button"
                    className="book-search-history-remove"
                    onClick={() => removeHistory(term)}
                    aria-label={`删除历史「${term}」`}
                  >
                    <HiX />
                  </button>
                </li>
              ))}
            </ul>
          </div>
        );
      }
      return <div className="book-search-status">输入关键词，搜索本书全部章节</div>;
    }
    if (!results.length) {
      return <div className="book-search-status">没有匹配「{query.trim()}」的内容</div>;
    }
    return (
      <ul className="book-search-list" ref={listRef}>
        {results.map((r, i) => (
          <li key={`${r.url}-${i}`}>
            <button
              type="button"
              className={`book-search-item${i === selected ? ' is-selected' : ''}`}
              onMouseMove={() => setSelected(i)}
              onClick={() => go(r)}
            >
              <div className="book-search-item-heading">{highlight(r.heading, terms)}</div>
              {r.snippet && (
                <div className="book-search-item-snippet">
                  {bodyIndexed ? highlight(r.snippet, terms) : r.snippet}
                </div>
              )}
              {r.docTitle && r.docTitle !== r.heading && (
                <div className="book-search-item-doc">{r.docTitle}</div>
              )}
            </button>
          </li>
        ))}
      </ul>
    );
  };

  return ReactDOM.createPortal(
    <div className="book-search-backdrop" onClick={onClose}>
      <div
        className="book-search-modal"
        role="dialog"
        aria-modal="true"
        aria-label="书内搜索"
        onClick={(event) => event.stopPropagation()}
        onKeyDown={handleKeyDown}
      >
        <div className="book-search-input-row">
          <HiSearch className="book-search-input-icon" aria-hidden="true" />
          <input
            ref={inputRef}
            type="text"
            className="book-search-input search-input"
            placeholder="搜索本书内容…"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            spellCheck={false}
            autoComplete="off"
            aria-label="搜索本书内容"
          />
          <button
            type="button"
            className="book-search-close"
            onClick={onClose}
            aria-label="关闭搜索"
          >
            <HiX />
          </button>
        </div>

        <div className="book-search-body">{renderBody()}</div>

        <div className="book-search-footer">
          {indexState === 'ready' && results.length > 0 && (
            <span className="book-search-count">{results.length} 条结果</span>
          )}
          <span className="book-search-hints">
            <kbd>↑</kbd><kbd>↓</kbd> 选择
            <kbd>↵</kbd> 跳转
            <kbd>esc</kbd> 关闭
          </span>
        </div>
      </div>
    </div>,
    document.body
  );
}

export default SearchModal;
