import { useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import {
  readSearchJumpState,
  flashSectionHits,
  clearSectionHits,
  FLASH_MS
} from '../services/search/searchJump';

// Flash the section an in-book search result lands on: a soft tint on the
// heading (via the .doc-search-jump class) plus a stronger mark on each literal
// query hit. After FLASH_MS it clears the flash, restores the DOM, and strips
// the #section from the address bar so a refresh won't re-jump (and re-flash).
//
// `headings` is the list of rendered headings, passed in so the effect re-runs
// once their DOM (and slugified ids) actually exist — the same readiness signal
// DocContent's scroll-to-hash effect waits on. Scoped to search jumps: ordinary
// TOC / deep-link jumps carry no jump state and stay quiet.
export function useSearchJumpHighlight(headings) {
  const location = useLocation();

  useEffect(() => {
    const jump = readSearchJumpState(location.state);
    if (!jump) {
      return undefined;
    }
    const id = location.hash ? location.hash.slice(1) : '';
    if (!id || !headings.length) {
      return undefined;
    }
    const element = document.getElementById(id);
    if (!element) {
      return undefined;
    }

    element.classList.add('doc-search-jump');
    const marks = flashSectionHits(element, jump.terms);
    const timer = setTimeout(() => {
      element.classList.remove('doc-search-jump');
      clearSectionHits(marks);
      // Strip the #section with history.replaceState rather than navigate() so
      // React Router's location doesn't change — that would trip DocContent's
      // scroll-to-top effect and yank the reader back to the top.
      if (window.location.hash) {
        window.history.replaceState(
          window.history.state,
          '',
          window.location.pathname + window.location.search
        );
      }
    }, FLASH_MS);

    return () => {
      clearTimeout(timer);
      element.classList.remove('doc-search-jump');
      clearSectionHits(marks);
    };
    // location.key changes per navigation, so re-clicking the same result
    // re-triggers the flash; location.state carries the jump payload.
  }, [headings, location.hash, location.pathname, location.key, location.state]);
}
