// Runtime client for in-book search.
//
// Lazy-loads the build-time index for one book (public/search-index/<id>.json,
// produced by scripts/build-search-index.mjs) and runs queries fully in the
// browser. Mirrors the generator: same tokenizer, same delta encoding, idf
// from body postings, heading matches weighted via the separate hidx.

import { tokenize } from './tokenize.mjs';

// In-memory caches keyed by bookId. `inflight` dedupes concurrent loads so two
// quick ⌘K presses don't fetch the same index twice.
const indexCache = new Map();
const inflight = new Map();

const HEADING_BOOST = 2; // a heading hit counts this many body hits' worth

function indexUrl(bookId) {
  const base = process.env.PUBLIC_URL || '';
  return `${base}/search-index/${encodeURIComponent(bookId)}.json`;
}

// Undo the generator's delta encoding: [first, d1, d2, ...] -> [s0, s1, ...].
function decodeDeltas(deltas) {
  if (!deltas || !deltas.length) {
    return [];
  }
  const out = new Array(deltas.length);
  let acc = 0;
  for (let i = 0; i < deltas.length; i += 1) {
    acc += deltas[i];
    out[i] = acc;
  }
  return out;
}

// Fetch + cache a book's index. Resolves to the parsed index, or null if the
// book has no index file (e.g. an empty book) or the request fails.
export function loadBookIndex(bookId) {
  if (!bookId) {
    return Promise.resolve(null);
  }
  if (indexCache.has(bookId)) {
    return Promise.resolve(indexCache.get(bookId));
  }
  if (inflight.has(bookId)) {
    return inflight.get(bookId);
  }

  const promise = fetch(indexUrl(bookId))
    .then((res) => (res.ok ? res.json() : null))
    .then((data) => {
      indexCache.set(bookId, data);
      inflight.delete(bookId);
      return data;
    })
    .catch(() => {
      indexCache.set(bookId, null);
      inflight.delete(bookId);
      return null;
    });

  inflight.set(bookId, promise);
  return promise;
}

// Run a query against a loaded index. Returns ranked results:
//   { url, path, anchor, docTitle, heading, snippet, score, matchCount }
// Ranking: sections matching more distinct query tokens come first; ties break
// on summed idf (with heading hits boosted).
export function searchBook(index, query, { limit = 30 } = {}) {
  if (!index || !index.secs) {
    return [];
  }

  const tokens = [...new Set(tokenize(query))];
  if (!tokens.length) {
    return [];
  }

  const N = index.secs.length || 1;
  const score = new Map();      // secIdx -> summed weighted idf
  const matchCount = new Map(); // secIdx -> distinct query tokens matched

  for (const token of tokens) {
    const body = decodeDeltas(index.idx[token]);
    const head = decodeDeltas(index.hidx?.[token]);
    if (!body.length && !head.length) {
      continue;
    }

    // idf from body document frequency (sections containing the token).
    const df = body.length || 1;
    const idf = Math.log(1 + N / (1 + df));

    const seenForToken = new Set();
    for (const sec of body) {
      score.set(sec, (score.get(sec) || 0) + idf);
      seenForToken.add(sec);
    }
    for (const sec of head) {
      score.set(sec, (score.get(sec) || 0) + idf * HEADING_BOOST);
      seenForToken.add(sec);
    }
    for (const sec of seenForToken) {
      matchCount.set(sec, (matchCount.get(sec) || 0) + 1);
    }
  }

  const ranked = [...score.keys()].sort((a, b) => {
    const mc = (matchCount.get(b) || 0) - (matchCount.get(a) || 0);
    if (mc !== 0) {
      return mc;
    }
    return (score.get(b) || 0) - (score.get(a) || 0);
  });

  return ranked.slice(0, limit).map((secIdx) => {
    const sec = index.secs[secIdx];
    const doc = index.docs[sec.d] || {};
    const anchor = sec.a || '';
    const path = doc.p || '';
    return {
      url: anchor ? `${path}#${anchor}` : path,
      path,
      anchor,
      docTitle: doc.t || '',
      heading: sec.h || '',
      snippet: sec.s || '',
      score: score.get(secIdx) || 0,
      matchCount: matchCount.get(secIdx) || 0
    };
  });
}

// Split a raw query into the literal terms a UI should highlight (whitespace
// separated, lowercased, longest first so multi-char terms win over substrings).
export function queryHighlightTerms(query) {
  return String(query || '')
    .toLowerCase()
    .split(/\s+/)
    .map((t) => t.trim())
    .filter(Boolean)
    .sort((a, b) => b.length - a.length);
}

function escapeRegExp(str) {
  return String(str).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Split `text` into consecutive { text, isHit } segments, where isHit marks the
// runs that match any highlight term (case-insensitive). The single matching
// primitive shared by the search modal (renders <mark> vnodes from the result
// snippets) and the in-doc jump flash (wraps DOM <mark>s), so both highlight
// exactly the same way. `terms` come from queryHighlightTerms.
export function splitByTerms(text, terms) {
  const safe = String(text || '');
  const escaped = (terms || []).map(escapeRegExp).filter(Boolean);
  if (!safe || !escaped.length) {
    return [{ text: safe, isHit: false }];
  }
  const re = new RegExp(`(${escaped.join('|')})`, 'gi');
  const segments = [];
  let last = 0;
  let match;
  while ((match = re.exec(safe)) !== null) {
    if (match.index > last) {
      segments.push({ text: safe.slice(last, match.index), isHit: false });
    }
    segments.push({ text: match[0], isHit: true });
    last = match.index + match[0].length;
    if (match.index === re.lastIndex) {
      re.lastIndex += 1; // guard against a zero-width match looping forever
    }
  }
  if (last < safe.length) {
    segments.push({ text: safe.slice(last), isHit: false });
  }
  return segments;
}
