// In-book "search jump" — the cross-page contract and DOM highlighting for
// landing on a search result. The search modal (producer) stamps the navigation
// via buildSearchJumpState(); the target page's useSearchJumpHighlight hook
// (consumer) reads it with readSearchJumpState() and flashes the matched
// section. Keeping the contract in one module is what stops the producer and
// consumer from drifting on a stringly-typed location.state shape.
//
// React-free on purpose: only the nav-state shape and pure DOM helpers live
// here; the React wiring is in hooks/useSearchJumpHighlight.js.

import { splitByTerms } from './searchClient';

// How long the landed-on section stays highlighted, in ms.
export const FLASH_MS = 2000;

// A section runs from its heading up to the next heading of any level.
const SECTION_HEADING_SELECTOR = 'h1, h2, h3, h4, h5, h6';
// Don't wrap matches inside these — code blocks/scripts shouldn't be rewritten,
// and MARK avoids double-wrapping.
const HIT_SKIP_TAGS = new Set(['PRE', 'SCRIPT', 'STYLE', 'MARK']);

// --- navigation-state contract (producer <-> consumer agree here, once) ------

export function buildSearchJumpState(terms) {
  return { docSearchJump: true, terms: Array.isArray(terms) ? terms : [] };
}

export function readSearchJumpState(state) {
  if (!state || !state.docSearchJump) {
    return null;
  }
  return { terms: Array.isArray(state.terms) ? state.terms : [] };
}

// --- DOM highlighting --------------------------------------------------------

// The heading element plus every following sibling up to the next heading.
function sectionNodes(headingEl) {
  const nodes = [headingEl];
  let n = headingEl.nextElementSibling;
  while (n && !n.matches(SECTION_HEADING_SELECTOR)) {
    nodes.push(n);
    n = n.nextElementSibling;
  }
  return nodes;
}

// Non-empty text nodes under `root`, skipping HIT_SKIP_TAGS subtrees.
function collectTextNodes(root) {
  const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
    acceptNode(node) {
      if (!node.nodeValue || !node.nodeValue.trim()) {
        return NodeFilter.FILTER_REJECT;
      }
      for (let p = node.parentNode; p && p !== root.parentNode; p = p.parentNode) {
        if (HIT_SKIP_TAGS.has(p.nodeName)) {
          return NodeFilter.FILTER_REJECT;
        }
      }
      return NodeFilter.FILTER_ACCEPT;
    }
  });
  const out = [];
  while (walker.nextNode()) {
    out.push(walker.currentNode);
  }
  return out;
}

// Wrap every query-term hit inside the heading's section in <mark>, returning
// the created nodes so they can be unwrapped later. Pure transient DOM.
export function flashSectionHits(headingEl, terms) {
  if (!headingEl || !terms || !terms.length) {
    return [];
  }
  const created = [];
  for (const root of sectionNodes(headingEl)) {
    for (const textNode of collectTextNodes(root)) {
      const segments = splitByTerms(textNode.nodeValue, terms);
      if (!segments.some((seg) => seg.isHit)) {
        continue;
      }
      const frag = document.createDocumentFragment();
      for (const seg of segments) {
        if (seg.isHit) {
          const mark = document.createElement('mark');
          mark.className = 'doc-search-hit-flash';
          mark.textContent = seg.text;
          frag.appendChild(mark);
          created.push(mark);
        } else if (seg.text) {
          frag.appendChild(document.createTextNode(seg.text));
        }
      }
      textNode.parentNode.replaceChild(frag, textNode);
    }
  }
  return created;
}

// Unwrap the <mark> nodes created above, restoring the original text so the DOM
// React rendered is left intact.
export function clearSectionHits(marks) {
  for (const mark of marks) {
    const parent = mark.parentNode;
    if (parent) {
      parent.replaceChild(document.createTextNode(mark.textContent), mark);
      parent.normalize();
    }
  }
}
