import React, { useCallback, useEffect, useState } from 'react';
import SearchModal from './SearchModal';
import { loadBookIndex } from '../../services/search/searchClient';

// Custom event any in-book UI can dispatch to open search without prop
// threading (e.g. the sidebar trigger button). See openBookSearch().
export const OPEN_BOOK_SEARCH_EVENT = 'open-book-search';

export function openBookSearch() {
  window.dispatchEvent(new CustomEvent(OPEN_BOOK_SEARCH_EVENT));
}

function isEditableTarget(target) {
  if (!(target instanceof HTMLElement)) {
    return false;
  }
  return Boolean(target.closest('input, textarea, select, [contenteditable="true"]'));
}

// Controller mounted once per book (inside DocsLayout). Owns the open state,
// the ⌘K / Ctrl+K / "/" shortcuts and the open-book-search event, and renders
// the modal. `bookId` decides which prebuilt index the modal loads.
function BookSearch({ bookId }) {
  const [open, setOpen] = useState(false);

  const close = useCallback(() => setOpen(false), []);

  useEffect(() => {
    const onOpenEvent = () => setOpen(true);

    const onKeyDown = (event) => {
      // ⌘K / Ctrl+K from anywhere.
      if ((event.metaKey || event.ctrlKey) && !event.altKey && (event.key === 'k' || event.key === 'K')) {
        event.preventDefault();
        setOpen((v) => !v);
        return;
      }
      // "/" as a quick-open, but not while typing in a field.
      if (event.key === '/' && !event.metaKey && !event.ctrlKey && !event.altKey && !isEditableTarget(event.target)) {
        event.preventDefault();
        setOpen(true);
      }
    };

    window.addEventListener(OPEN_BOOK_SEARCH_EVENT, onOpenEvent);
    window.addEventListener('keydown', onKeyDown);
    return () => {
      window.removeEventListener(OPEN_BOOK_SEARCH_EVENT, onOpenEvent);
      window.removeEventListener('keydown', onKeyDown);
    };
  }, []);

  // Close when navigating to a different book.
  useEffect(() => {
    setOpen(false);
  }, [bookId]);

  // Prefetch this book's search index once the page is idle — so reading is
  // never slowed (the article fetches/renders first), yet the index is almost
  // always already cached by the time the user actually opens search.
  // loadBookIndex dedupes + caches, so a real search just reuses this.
  useEffect(() => {
    if (!bookId) {
      return undefined;
    }
    const prefetch = () => loadBookIndex(bookId);
    if (typeof window.requestIdleCallback === 'function') {
      const id = window.requestIdleCallback(prefetch, { timeout: 3000 });
      return () => window.cancelIdleCallback?.(id);
    }
    const id = setTimeout(prefetch, 1200);
    return () => clearTimeout(id);
  }, [bookId]);

  if (!open) {
    return null;
  }
  return <SearchModal bookId={bookId} onClose={close} />;
}

export default BookSearch;
