// Resolve internal Markdown links to in-site routes.
//
// Markdown authors write cross-page links against the *file* layout
// (`./sibling.md`, `../other.md`, or rust-course's repo-absolute `/src/foo.md`)
// — the same convention VSCode / GitHub / mdbook follow. Our site serves
// *routes* (`/ai-insights/<slug>`, `/rust-course/<chapter>`), and a book's
// in-site path does NOT always mirror its file path (ai-insights flattens away
// the date folders). So we canonicalize both the link target and every meta
// `file` to a book-relative key, then look the target up in the book's
// file->path index. A lookup miss returns null and the caller leaves the href
// untouched — no regression for already-working or non-document links.
//
// This module is dependency-free and pure on purpose (see docLinkResolver.test.js).

// http:, https:, mailto:, tel:, data:, etc. — anything with a scheme is external.
const EXTERNAL_PROTOCOL = /^[a-z][a-z0-9+.-]*:/i;
const MARKDOWN_EXT = /\.mdx?$/i;

// Reduce any Markdown `file` reference (a stored meta `file` or a resolved link
// target) to a book-relative key:
//   https://cdn.jsdelivr.net/gh/sunface/rust-course@main/src/a/b.md -> src/a/b
//   https://pic.gitlab.cx/gh/sunface/rust-course@main/src/a/b.md    -> src/a/b
//   /docs/ai-insights/2026-06/08/x.md                               -> ai-insights/2026-06/08/x
//   /src/compiler/pitfalls/stack-overflow.md                        -> src/compiler/pitfalls/stack-overflow
// Stripping the host means the cdn vs. proxy mirror (pic.gitlab.cx) collapse to
// the same key, so meta `file`s and the URLs we render from still match.
export function canonicalDocKey(fileRef) {
  if (!fileRef) {
    return '';
  }

  let key = String(fileRef).split('#')[0].split('?')[0];

  // Remote CDN/proxy form: keep only the repo-relative tail after `@<ref>/`.
  const refMatch = key.match(/@[^/]+\/(.+)$/);
  if (refMatch) {
    key = refMatch[1];
  } else {
    // Local content always lives under a `/docs/` root; drop anything before it
    // (incl. a PUBLIC_URL prefix). Otherwise strip a generic absolute-URL host.
    key = key.replace(/^.*?\/docs\//, '').replace(/^https?:\/\/[^/]+\//i, '');
  }

  return key
    .replace(/^\/+/, '')
    .replace(MARKDOWN_EXT, '')
    .replace(/\/+$/, '');
}

// Build the canonical-key -> in-site-path lookup for a book's leaf documents.
// `leaves` is an array of { file, path } (e.g. from flattenChapters(meta)).
export function buildFileToPathIndex(leaves = []) {
  const index = new Map();

  for (const leaf of leaves) {
    if (!leaf || !leaf.file || !leaf.path) {
      continue;
    }
    const key = canonicalDocKey(leaf.file);
    // First writer wins — meta order is authoritative for duplicate tails.
    if (key && !index.has(key)) {
      index.set(key, leaf.path);
    }
  }

  return index;
}

// Resolve a relative link (`./x`, `../x`, `x`) against the current document's
// canonical key, returning the canonical key of the target.
function joinRelativeKey(currentKey, relativePath) {
  const segments = currentKey.split('/').slice(0, -1); // drop the current file name
  const relSegments = relativePath.replace(MARKDOWN_EXT, '').split('/');

  for (const segment of relSegments) {
    if (segment === '' || segment === '.') {
      continue;
    }
    if (segment === '..') {
      segments.pop();
      continue;
    }
    segments.push(segment);
  }

  return segments.join('/');
}

// Map a Markdown link href to an in-site route, or null to leave it untouched.
//   { href, currentFile, fileToPath } -> { to, anchor } | null
// `currentFile` is the URL the current document was fetched from (the resolved
// markdownUrl); `fileToPath` is the Map from buildFileToPathIndex.
export function resolveInternalDocHref({ href, currentFile, fileToPath } = {}) {
  if (!href || typeof href !== 'string' || !fileToPath) {
    return null;
  }

  const trimmed = href.trim();

  // Pure in-page anchor — leave to native/hash scrolling.
  if (trimmed.startsWith('#')) {
    return null;
  }

  // Protocol-relative (`//host`) and any scheme (http/mailto/tel/...) are external.
  if (trimmed.startsWith('//') || EXTERNAL_PROTOCOL.test(trimmed)) {
    return null;
  }

  const hashIndex = trimmed.indexOf('#');
  const rawPath = hashIndex === -1 ? trimmed : trimmed.slice(0, hashIndex);
  const anchor = hashIndex === -1 ? '' : trimmed.slice(hashIndex + 1);

  // Only internal Markdown documents are route-mapped. Images, assets, and
  // already-routed paths pass through untouched.
  if (!MARKDOWN_EXT.test(rawPath)) {
    return null;
  }

  const targetKey = rawPath.startsWith('/')
    ? canonicalDocKey(rawPath) // repo/site-absolute, e.g. rust-course's /src/foo.md
    : joinRelativeKey(canonicalDocKey(currentFile), rawPath); // ./ ../ bare

  const to = targetKey ? fileToPath.get(targetKey) : null;
  if (!to) {
    return null;
  }

  return { to, anchor };
}
